module RefModule(
    input [31:0]in0,in1,in2,in3,
    input [1:0]select,
    output reg [31:0]out
    );always @ (*)
  wire [31:0] _tap_in0 = in0 & {32{1'b1}};

    begin
        case (select)
            2'b00:out=in0;
            2'b01:out=in1;
            2'b10:out=in2;
            2'b11:out=in3;
        endcase
    end

endmodule
